void neverlose::fix_signatures()
{
	auto logger = ENTER_LOGGER(logman);

	printf("    [fix_sig] scanning %zu signatures...\n", g_signatures.size()); fflush(stdout);
	for (size_t i = 0; i < g_signatures.size(); i++)
	{
		auto& sig = g_signatures[i];
		HMODULE hMod = GetModuleHandle(sig.module_name);
		if (!hMod)
		{
			printf("    [fix_sig] [%zu] FATAL: 0x%08lX - %ls not loaded!\n", i, sig.address, sig.module_name); fflush(stdout);
			panic("%ls is not loaded! (sig 0x%08lX)", sig.module_name, sig.address);
		}

		MODULEINFO minfo{ 0 };
		GetModuleInformation(GetCurrentProcess(), hMod, &minfo, sizeof(minfo));

		PVOID found = FindPattern(minfo.lpBaseOfDll, minfo.SizeOfImage, (PBYTE)sig.signature, sig.signature_len, 0xCC, 0);
		if (found)
		{
			*(PPVOID)sig.address = ((PBYTE)found + sig.offset);
			logger << "Fixed function ptr at " << (PVOID)sig.address << " function at " << *(PPVOID)sig.address << '\n';
		}
		else
		{
			printf("    [fix_sig] [%zu] FATAL: pattern not found for 0x%08lX in %ls\n", i, sig.address, sig.module_name); fflush(stdout);
			panic("Signature not found for 0x%08lX in %ls", sig.address, sig.module_name);
		}
	};

	printf("    [fix_sig] scanning %zu derefed signatures...\n", g_derefed_signatures.size()); fflush(stdout);
	for (size_t i = 0; i < g_derefed_signatures.size(); i++)
	{
		auto& sig = g_derefed_signatures[i];
		HMODULE hMod = GetModuleHandle(sig.module_name);
		if (!hMod)
		{
			printf("    [fix_sig] [deref %zu] FATAL: 0x%08lX - %ls not loaded!\n", i, sig.address, sig.module_name); fflush(stdout);
			panic("%ls is not loaded! (deref sig 0x%08lX)", sig.module_name, sig.address);
		}

		MODULEINFO minfo{ 0 };
		GetModuleInformation(GetCurrentProcess(), hMod, &minfo, sizeof(minfo));

		PVOID found = FindPattern(minfo.lpBaseOfDll, minfo.SizeOfImage, (PBYTE)sig.signature, sig.signature_len, 0xCC, 0);
		if (found)
		{
			*(PPVOID)sig.address = *(PPVOID)((PBYTE)found + sig.offset);
			logger << "Fixed class import at " << (PVOID)sig.address << " class at " << *(PPVOID)sig.address << '\n';
		}
		else
		{
			printf("    [fix_sig] [deref %zu] FATAL: pattern not found for 0x%08lX in %ls\n", i, sig.address, sig.module_name); fflush(stdout);
			panic("Deref signature not found for 0x%08lX in %ls", sig.address, sig.module_name);
		}
	};
	printf("    [fix_sig] done\n"); fflush(stdout);
};
